// NODO: DPF (Dynamic Payload Factory)
// VERSIONE: 2.2 - Supporto Multi-Versione (Gemini 2.5 vs Gemini 3)

// --- 1. Estrazione degli Input ---
const item = $input.first().json;

const systemInstruction = item.SystemInstruction;
const prompt = item.Prompt;
const modelChoiceUrl = item.ModelChoice || ""; 
const useThinking = item.thinking === true; 
const base64Data = item.data;
const mimeType = item.mimeType;

// Validazione input essenziali
if (!systemInstruction || !prompt || !modelChoiceUrl) {
    throw new Error('DPF Error: Input essenziali mancanti (SystemInstruction, Prompt, o ModelChoice).');
}

// --- 2. Rilevamento Versione Modello e Configurazione Thinking ---
const isGemini3 = modelChoiceUrl.toLowerCase().includes('gemini-3');
const isFlash = modelChoiceUrl.toLowerCase().includes('flash');

let thinkingConfig = {};

if (isGemini3) {
    // Logica per Gemini 3 (thinkingLevel)
    // Nota: "MINIMAL" è supportato da Flash, per Pro si usa solitamente "LOW" come minimo
    if (useThinking) {
        thinkingConfig.thinkingLevel = "HIGH";
    } else {
        thinkingConfig.thinkingLevel = isFlash ? "MINIMAL" : "LOW";
    }
} else {
    // Logica per Gemini 2.5 (thinkingBudget)
    thinkingConfig.thinkingBudget = useThinking ? -1 : 0;
}

// --- 3. Costruzione della Sezione "contents" ---
const contentsParts = [{ "text": prompt }];
if (base64Data && mimeType) {
    contentsParts.push({
        "inline_data": {
            "mime_type": mimeType,
            "data": base64Data
        }
    });
}

// --- 4. Costruzione del Payload Finale ---
let finalPayload = {
    "system_instruction": {
        "parts": [{ "text": systemInstruction }]
    },
    "contents": [
        {
            "role": "user",
            "parts": contentsParts
        }
    ],
    "generation_config": {
        "thinkingConfig": thinkingConfig,
        "response_mime_type": "application/json"
    }
};

// --- 5. Preparazione dell'Output ---
const outputItem = { ...item };

// Pulizia campi
delete outputItem.SystemInstruction;
delete outputItem.Prompt;
delete outputItem.ModelChoice;
delete outputItem.thinking;
delete outputItem.data;
delete outputItem.mimeType;
delete outputItem.grounding; // Assicuriamoci che sia rimosso
delete outputItem.user_request; 

outputItem.finalApiUrl = modelChoiceUrl;
outputItem.geminiApiCallPayload = finalPayload;

return [{ json: outputItem }];

// NODO: SiteBoS Billing - Dynamic Edition
// VERSIONE: 8.1 - Listino pre-unificato in ingresso e Matching Intelligente

// --- 1. RECUPERO LISTINO UNIFICATO IN INGRESSO ---
const item = $input.first().json;

// Estraiamo il listino prezzi dall'oggetto pre-unificato "listino_prezzi"
const pricesDoc = item.listino_prezzi || {};
let dynamicPricing = pricesDoc.listino_prezzi || [];

// Fallback locale di sicurezza se l'array dei prezzi risulta vuoto o non integro
if (!Array.isArray(dynamicPricing) || dynamicPricing.length === 0) {
    dynamicPricing = [
        { model_pattern: "lite", rates: { in: 0.10, out: 0.40 }, has_threshold: false },
        { model_pattern: "2.5-flash", rates: { in: 0.30, out: 2.50 }, has_threshold: false },
        { model_pattern: "3-flash", rates: { in: 0.50, out: 3.00 }, has_threshold: false },
        { model_pattern: "3.5-flash", rates: { in: 1.50, out: 9.00 }, has_threshold: false },
        { 
            model_pattern: "pro", 
            rates: {
                base: { in: 2.00, out: 12.00 },
                long: { in: 4.00, out: 18.00 }
            },
            has_threshold: true,
            threshold_tokens: 200000
        }
    ];
}

// Il Moltiplicatore che copre tutto (Server, n8n, Mongo, Valore IP)
const X_MULTIPLIER = 1200; 

// --- 2. ESTRAZIONE METADATI E CONTESTO ---
if (!item.usageMetadata || !item.modelVersion) {
    return [{ json: { ...item, billing_error: "Metadata di utilizzo o modelVersion mancanti nel payload" } }];
}

const meta = item.usageMetadata;
const model = item.modelVersion.toLowerCase(); // Risolve ad esempio: "gemini-3.5-flash"
const inputTokens = meta.promptTokenCount || 0;
const outputTokens = meta.candidatesTokenCount || 0;

// --- 3. MATCHING INTELLIGENTE ---
// Ordiniamo le regole del listino per lunghezza decrescente del pattern.
// In questo modo i pattern più specifici (es. "3.5-flash") vengono valutati prima di quelli più generici (es. "flash").
const sortedRules = [...dynamicPricing].sort((a, b) => b.model_pattern.length - a.model_pattern.length);

let matchedRule = null;
for (const rule of sortedRules) {
    if (model.includes(rule.model_pattern.toLowerCase())) {
        matchedRule = rule;
        break;
    }
}

// Fallback cautelativo se nessun pattern corrisponde al modello restituito dall'API
if (!matchedRule) {
    matchedRule = sortedRules.find(r => r.model_pattern.includes("3-flash")) || sortedRules[0];
}

// --- 4. SELEZIONE DELLE TARIFFE (CON SOGLIA) ---
let rates = { in: 0, out: 0 };

if (matchedRule.has_threshold) {
    const threshold = matchedRule.threshold_tokens || 200000;
    if (inputTokens > threshold) {
        rates = matchedRule.rates.long;
    } else {
        rates = matchedRule.rates.base;
    }
} else {
    rates = matchedRule.rates;
}

// --- 5. CALCOLO COSTO USD E CREDITI ---
const costUSD = ((inputTokens / 1e6) * rates.in) + ((outputTokens / 1e6) * rates.out);

// Calcolo finale dei crediti garantendo un valore minimo di 1 e l'arrotondamento per eccesso
let finalCredits = Math.max(costUSD * X_MULTIPLIER, 1);
finalCredits = Math.ceil(finalCredits);

// --- 6. PREPARAZIONE OUTPUT ---
return [{
    json: {
        billing: {
            model: model,
            matched_pattern: matchedRule.model_pattern,
            is_long_context: !!(matchedRule.has_threshold && inputTokens > (matchedRule.threshold_tokens || 200000)),
            usage: { in: inputTokens, out: outputTokens },
            usd_cost: Number(costUSD.toFixed(6)),
            credits_deducted: finalCredits
        }
    }
}];

// NODO: Brutal_Force_Universal_Content_Extractor
// VERSIONE: 1.1 - Error Pin Edition

// --- 1. PREPARAZIONE ---
const item = $input.first().json;
let allTextContent = []; 

// Navigazione sicura
const candidates = item.candidates;

// SE NON CI SONO CANDIDATI: Lanciamo l'errore per finire nell'uscita RETRY
if (!Array.isArray(candidates) || candidates.length === 0) {
    throw new Error("Gemini ha risposto senza candidati (Risposta Vuota).");
}

// --- 2. CICLO DI ESTRAZIONE ---
for (const candidate of candidates) {
    const parts = candidate.content?.parts;
    if (!Array.isArray(parts)) continue;

    for (const part of parts) {
        if (part && typeof part.text === 'string' && part.text.trim() !== '') {
            allTextContent.push(part.text.trim());
        }
    }
}

// --- 3. CONSOLIDAMENTO E VALIDAZIONE ---
const finalText = allTextContent.join('\n\n');

// SE NON C'È TESTO: Lanciamo l'errore
if (finalText === '') {
    throw new Error("Nessun contenuto testuale trovato nella risposta di Gemini.");
}

// --- 4. SUCCESSO ---
// Restituiamo solo l'output utile per il parser JSON successivo
return [{ 
    json: { 
        sOUTPUT: finalText 
    } 
}];

// NODO: Brutal Force Parser V7 - Proactive Sanitization
// VERSIONE: 7.1 - SiteBoS Pin Error Edition

// --- FUNZIONI DI SANIFICAZIONE PROATTIVA ---

function closeBracketsQuotes(str) {
    let cleaned = str;
    const openBraces = (str.match(/{/g) || []).length;
    const closeBraces = (str.match(/}/g) || []).length;
    const openBrackets = (str.match(/\[/g) || []).length;
    const closeBrackets = (str.match(/]/g) || []).length;

    if (openBraces > closeBraces) cleaned += '}'.repeat(openBraces - closeBraces);
    if (openBrackets > closeBrackets) cleaned += ']'.repeat(openBrackets - closeBrackets);

    const unescapedQuotes = (str.match(/(?<!\\)"/g) || []).length;
    if (unescapedQuotes % 2 !== 0) cleaned += '"';

    return cleaned;
}

function removeTrailingCommas(str) {
    return str.replace(/,(\s*[}\]])/g, '$1');
}

function fixMissingCommas(str) {
    let cleaned = str;
    cleaned = cleaned.replace(/"\s*\n\s*"/g, '",\n"');
    cleaned = cleaned.replace(/}(\s*){/g, '},\n{');
    cleaned = cleaned.replace(/](\s*)\[/g, '],\n[');
    cleaned = cleaned.replace(/("\s*:\s*(?:"[^"]*"|[^,}\s]+))\s+"/g, '$1,"');
    return cleaned;
}

function sanitizeJsonString(str) {
    let result = str;
    result = closeBracketsQuotes(result);
    result = removeTrailingCommas(result);
    result = fixMissingCommas(result);
    return result;
}

function proactiveJsonParse(jsonString) {
    try {
        return JSON.parse(jsonString);
    } catch (directError) {
        try {
            const sanitized = sanitizeJsonString(jsonString);
            return JSON.parse(sanitized);
        } catch (sanitizedError) {
            throw new Error(`Impossibile riparare il JSON: ${sanitizedError.message}`);
        }
    }
}

// --- LOGICA PRINCIPALE ---

const item = $input.first().json;
const rawString = item.sOUTPUT; // Leggiamo l'output consolidato dal nodo precedente

try {
    if (!rawString || rawString.trim() === '') {
        throw new Error("Input sOUTPUT vuoto o non valido.");
    }

    // Preprocessing markdown
    let cleanedString = rawString.replace(/^```(?:json)?\s*/, '').replace(/\s*```$/, '');

    // Isolamento JSON
    const firstBrace = cleanedString.indexOf('{');
    const lastBrace = cleanedString.lastIndexOf('}');

    if (firstBrace === -1 || lastBrace === -1 || lastBrace < firstBrace) {
        throw new Error("Nessuna struttura JSON trovata nella stringa.");
    }

    const stringToParse = cleanedString.substring(firstBrace, lastBrace + 1);
    const parsedJson = proactiveJsonParse(stringToParse);

    // USCITA DI SUCCESSO (Pin Verde)
    // Restituiamo il JSON pulito pronto per il Billing
    return [{
        json: {
            output: parsedJson
        }
    }];

} catch (error) {
    // USCITA ERRORE (Pin Rosso)
    // Lanciando l'errore, n8n userà l'uscita "Error" se configurata
    throw new Error(`Parser V7 Fallito: ${error.message}`);
}

// NODO: AI_Output_Cleaner & Final Formatter
// VERSIONE: 2.0 - Con logica di rename dinamico
// OBIETTIVO: Pulire i campi tecnici e formattare l'output finale
//            secondo la chiave specificata in 'outputRename'.

try {
  // 1. Ottieni l'item di input completo
  const item = $input.first().json;

  // 2. Crea una copia dell'item
  const cleanedItem = { ...item };

  // 3. Elenco dei campi di primo livello da rimuovere
  const fieldsToRemove = [
    'SystemInstruction',
    'Prompt',
    'output_structure',
    'ModelChoice',
    'GeminiKey',
    'grounding',
    'thinking',
    'finalApiUrl',
    'geminiApiCallPayload',
    'data',
    'path',
    'errorPath',
    'mimeType'
  ];

  // 4. Rimuovi i campi tecnici
  for (const field of fieldsToRemove) {
    if (field in cleanedItem) {
      delete cleanedItem[field];
    }
  }

  // 5. --- NUOVA LOGICA DI RENAME DINAMICO ---
  // Legge la chiave desiderata per l'output. Se non fornita, usa 'output' come default.
  const outputKey = cleanedItem.outputRename || 'output';

  // Verifica che il campo 'output' esista (prodotto dal parser)
  if ('output' in cleanedItem) {
    // Salva il risultato finale
    const finalResult = cleanedItem.output;

    // Rimuovi il campo 'output' originale e 'outputRename'
    delete cleanedItem.output;
    delete cleanedItem.outputRename;

    // Aggiungi il risultato con la nuova chiave dinamica
    cleanedItem[outputKey] = finalResult;
  } else {
    // Se non c'è un campo 'output', logga un avviso ma non far fallire il workflow
    console.warn("Output_Cleaner: Campo 'output' non trovato da rinominare.");
  }

  // 6. Restituisci l'oggetto finale, pulito e formattato
  return [{ json: cleanedItem }];

} catch (error) {
  console.error(`Errore critico nel nodo AI_Output_Cleaner: ${error.message}`);
  // In caso di errore, restituisci l'item originale per il debug
  return $input.all();
}

// NODO: Balance Updater & Transaction Merger
// VERSIONE: 1.2 - Dynamic Ledger Balance Lookup (Single Source of Truth)

// --- 1. Estrazione dati ---
const item = $input.first().json;

// --- 2. Determinazione del saldo precedente dal Ledger (billing_buffers) ---
let currentBalance = 0;
let foundInLedger = false;

if (item.last_message && item.last_message.data) {
    let lastTx = {};
    const rawData = item.last_message.data;

    try {
        // Parsing robusto del messaggio di memoria (LangChain format o JSON puro)
        if (typeof rawData === 'string') {
            lastTx = JSON.parse(rawData);
        } else if (rawData.content) {
            lastTx = JSON.parse(rawData.content);
        } else {
            lastTx = rawData;
        }

        if (lastTx && lastTx.final_balance !== undefined) {
            currentBalance = Number(lastTx.final_balance);
            foundInLedger = true;
            console.log(`Ledger Balance intercettato con successo: ${currentBalance}`);
        }
    } catch (e) {
        console.warn("Errore durante il parsing di last_message. Procedo con fallback.");
    }
}

if (!foundInLedger) {
    // Fallback su owner_data se non ci sono ancora record nel buffer transazioni
    currentBalance = Number(item.owner_data?.credits_balance || 0);
    console.log(`Fallback su owner_data Balance: ${currentBalance}`);
}

const billingData = item.billing || {}; 
const creditsToDeduct = Number(billingData.credits_deducted) || 0;

// --- 3. Calcolo nuovo saldo ---
const newBalance = currentBalance - creditsToDeduct;

// --- 4. Preparazione dell'Output ---
const outputItem = { ...item };

// Creiamo il summary che include tutti i dati di billing, previous e final_balance
outputItem.transaction_summary = {
    ...billingData,          // Esplode model, usd_cost, usage, credits_deducted, ecc.
    previous_balance: currentBalance,
    final_balance: newBalance,
    timestamp: new Date().toISOString()
};

// Aggiorniamo il saldo nell'anagrafica proprietario per propagazione cache di lettura veloce
if (outputItem.owner_data) {
    outputItem.owner_data.credits_balance = newBalance;
}

// Pulizia campi di query temporanei
delete outputItem.billing;
if (outputItem.last_message) {
    delete outputItem.last_message;
}

return [{ json: outputItem }];

/**
 * NODO: Update Stakeholder Balance (Minimal)
 */

const results = [];

for (const item of $input.all()) {
    const data = item.json;
    const stakeholder = data.stakeholder;
    const summary = data.transaction_summary;

    if (stakeholder && summary) {
        // 1. Applica il saldo finale calcolato
        stakeholder.commercial_profile.credit_balance.available_credits = summary.final_balance;

        // 2. Usa il timestamp del riepilogo per tutto
        const ts = summary.timestamp; // Es: "2026-03-02T17:21:41.227Z"

        stakeholder.commercial_profile.credit_balance.last_update = ts;
        stakeholder.commercial_profile.credit_balance.last_transaction_id = ts; // Usiamo il timestamp come ID
        stakeholder.metadata.last_updated = ts;
    }

    results.push({
        stakeholder_owner: stakeholder
    });
}

return results;

